// 2.8. Komponen: Modal Pembekuan Rutinitas (Freeze Routine)
const FreezeRoutineModal = ({ isOpen, onClose, onSave, routineTitle }) => {
  const [startDate, setStartDate] = useState("");
  const [endDate, setEndDate] = useState("");
  const [reason, setReason] = useState("");

  useEffect(() => {
    if (isOpen) {
      setStartDate("");
      setEndDate("");
      setReason("");
    }
  }, [isOpen]);

  if (!isOpen) return null;

  const handleSubmit = (e) => {
    e.preventDefault();
    if (!startDate || !endDate || !reason)
      return alert("Mohon lengkapi semua data");
    if (new Date(endDate) < new Date(startDate))
      return alert("Tanggal selesai tidak boleh sebelum tanggal mulai");

    onSave({ startDate, endDate, reason });
    onClose();
  };

  return (
    <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
      <div className="bg-white rounded-3xl shadow-2xl max-w-sm w-full p-8 border border-slate-100">
        <div className="flex justify-between items-center mb-6">
          <h3 className="text-xl font-bold text-slate-900 flex items-center gap-3">
            <div className="p-2 bg-blue-100 rounded-xl text-blue-600">
              <Snowflake size={20} />
            </div>
            Freeze Rutinitas
          </h3>
          <button
            onClick={onClose}
            className="p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
        </div>
        <div className="mb-4 bg-blue-50 text-blue-700 p-3 rounded-xl text-xs">
          <p className="font-bold">Info:</p>
          Rutinitas "{routineTitle}" tidak akan muncul di agenda dan tidak
          memengaruhi performa selama periode ini.
        </div>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-3">
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
                Mulai
              </label>
              <input
                type="date"
                className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl text-sm"
                value={startDate}
                onChange={(e) => setStartDate(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
                Selesai
              </label>
              <input
                type="date"
                className="w-full px-3 py-3 bg-white border border-slate-200 rounded-xl text-sm"
                value={endDate}
                onChange={(e) => setEndDate(e.target.value)}
              />
            </div>
          </div>
          <div>
            <label className="block text-xs font-bold text-slate-400 uppercase tracking-wider mb-2">
              Alasan
            </label>
            <input
              type="text"
              placeholder="Sakit, Liburan, Mudik..."
              className="w-full px-4 py-3 bg-white border border-slate-200 rounded-xl focus:outline-none focus:ring-2 focus:ring-blue-500 text-slate-800 shadow-sm"
              value={reason}
              onChange={(e) => setReason(e.target.value)}
            />
          </div>
          <button
            type="submit"
            className="w-full bg-blue-600 hover:bg-blue-700 text-white font-bold py-3.5 rounded-xl shadow-xl shadow-blue-200 transition-all active:scale-[0.98]"
          >
            Simpan Freeze
          </button>
        </form>
      </div>
    </div>
  );
};

// 2.9. Komponen: Modal Riwayat & Edit Pembekuan Rutinitas
const FreezeHistoryModal = ({
  isOpen,
  onClose,
  routine,
  onEditFreeze,
  onDeleteFreeze,
}) => {
  const [editingIndex, setEditingIndex] = useState(null);
  const [editForm, setEditForm] = useState({
    startDate: "",
    endDate: "",
    reason: "",
  });
  const [deleteConfirm, setDeleteConfirm] = useState({
    show: false,
    index: null,
  });

  useEffect(() => {
    if (isOpen) {
      setEditingIndex(null);
      setDeleteConfirm({ show: false, index: null });
    }
  }, [isOpen]);

  if (!isOpen || !routine) return null;

  // Trik: Menyimpan index asli sebelum array di-sort agar kita tidak salah mengedit/menghapus data
  const periods = (routine.freezePeriods || [])
    .map((p, idx) => ({ ...p, originalIndex: idx }))
    .sort((a, b) => new Date(b.startDate) - new Date(a.startDate));

  const handleEditClick = (period) => {
    setEditingIndex(period.originalIndex);
    setEditForm({
      startDate: period.startDate,
      endDate: period.endDate,
      reason: period.reason,
    });
  };

  const handleSaveEdit = (e, originalIndex) => {
    e.preventDefault();
    // Validasi: pastikan tanggal masuk akal
    if (new Date(editForm.endDate) < new Date(editForm.startDate)) return;
    if (onEditFreeze) onEditFreeze(routine.id, originalIndex, editForm);
    setEditingIndex(null);
  };

  const handleDeleteClick = (originalIndex) => {
    setDeleteConfirm({ show: true, index: originalIndex });
  };

  const executeDelete = () => {
    if (onDeleteFreeze && deleteConfirm.index !== null) {
      onDeleteFreeze(routine.id, deleteConfirm.index);
    }
    setDeleteConfirm({ show: false, index: null });
  };

  return (
    <>
      {/* Memanggil Modal Konfirmasi Kustom untuk menghapus riwayat freeze */}
      <ConfirmationModal
        isOpen={deleteConfirm.show}
        onClose={() => setDeleteConfirm({ show: false, index: null })}
        onConfirm={executeDelete}
        title="Hapus Riwayat Freeze?"
        message="Data pembekuan rutinitas ini akan dihapus permanen. Performa rutinitas di masa lalu mungkin akan terpengaruh."
        confirmText="Konfirmasi Hapus"
        confirmColor="bg-red-500 hover:bg-red-600 shadow-red-200"
      />

      <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/40 backdrop-blur-sm p-4 animate-in fade-in duration-200">
        <div className="bg-white rounded-3xl shadow-2xl max-w-sm w-full p-8 border border-slate-100 relative">
          <button
            onClick={onClose}
            className="absolute top-4 right-4 p-2 hover:bg-slate-100 rounded-full transition-colors"
          >
            <X size={20} className="text-slate-400" />
          </button>
          <div className="flex items-center gap-3 mb-6">
            <div className="p-3 bg-blue-50 text-blue-600 rounded-2xl">
              <Snowflake size={24} />
            </div>
            <div>
              <h3 className="font-bold text-lg text-slate-900">
                Riwayat Freeze
              </h3>
              <p className="text-xs text-slate-500 truncate max-w-[150px]">
                {routine.title}
              </p>
            </div>
          </div>

          <div className="space-y-3 max-h-[60vh] overflow-y-auto pr-2 custom-scrollbar">
            {periods.length === 0 ? (
              <div className="text-center py-8 text-slate-400">
                <p className="text-sm italic">Belum ada data pembekuan.</p>
              </div>
            ) : (
              periods.map((p) => {
                const today = new Date();
                today.setHours(0, 0, 0, 0);

                const start = parseLocalYMD(p.startDate);
                const end = parseLocalYMD(p.endDate);
                end.setHours(23, 59, 59, 999);

                const isActive = today >= start && today <= end;
                const isValid = start <= end;

                if (editingIndex === p.originalIndex) {
                  return (
                    <form
                      key={p.originalIndex}
                      onSubmit={(e) => handleSaveEdit(e, p.originalIndex)}
                      className="space-y-2 p-3 bg-slate-50 rounded-2xl border border-blue-200 shadow-sm animate-in fade-in"
                    >
                      <div className="grid grid-cols-2 gap-2">
                        <div>
                          <label className="text-[10px] font-bold text-slate-500 uppercase">
                            Mulai
                          </label>
                          <input
                            type="date"
                            required
                            className="w-full px-2 py-1.5 text-xs rounded-xl border border-slate-200"
                            value={editForm.startDate}
                            onChange={(e) =>
                              setEditForm({
                                ...editForm,
                                startDate: e.target.value,
                              })
                            }
                          />
                        </div>
                        <div>
                          <label className="text-[10px] font-bold text-slate-500 uppercase">
                            Selesai
                          </label>
                          <input
                            type="date"
                            required
                            className="w-full px-2 py-1.5 text-xs rounded-xl border border-slate-200"
                            value={editForm.endDate}
                            onChange={(e) =>
                              setEditForm({
                                ...editForm,
                                endDate: e.target.value,
                              })
                            }
                          />
                        </div>
                      </div>
                      <div>
                        <label className="text-[10px] font-bold text-slate-500 uppercase">
                          Alasan
                        </label>
                        <input
                          type="text"
                          required
                          className="w-full px-3 py-2 text-xs rounded-xl border border-slate-200"
                          value={editForm.reason}
                          onChange={(e) =>
                            setEditForm({ ...editForm, reason: e.target.value })
                          }
                        />
                      </div>
                      <div className="flex gap-2 pt-2">
                        <button
                          type="button"
                          onClick={() => setEditingIndex(null)}
                          className="flex-1 bg-slate-200 text-slate-600 text-xs py-2 rounded-xl font-bold hover:bg-slate-300 transition-colors"
                        >
                          Batal
                        </button>
                        <button
                          type="submit"
                          className="flex-1 bg-blue-600 text-white text-xs py-2 rounded-xl font-bold hover:bg-blue-700 shadow-lg shadow-blue-200 transition-colors"
                        >
                          Simpan
                        </button>
                      </div>
                    </form>
                  );
                }

                return (
                  <div
                    key={p.originalIndex}
                    className={`p-4 rounded-2xl border group relative transition-all ${isActive ? "bg-blue-50 border-blue-200 shadow-sm" : "bg-white border-slate-100 hover:border-slate-200"}`}
                  >
                    <div className="flex justify-between items-start mb-1">
                      <span
                        className={`text-xs font-bold pr-10 ${isActive ? "text-blue-700" : "text-slate-700"}`}
                      >
                        {isValid ? (
                          `${start.toLocaleDateString("id-ID", { day: "numeric", month: "short" })} - ${end.toLocaleDateString("id-ID", { day: "numeric", month: "short", year: "numeric" })}`
                        ) : (
                          <span className="line-through opacity-50">
                            {start.toLocaleDateString("id-ID", {
                              day: "numeric",
                              month: "short",
                            })}{" "}
                            (Dibatalkan)
                          </span>
                        )}
                      </span>
                      {isActive && (
                        <span className="text-[10px] bg-blue-600 text-white px-2 py-0.5 rounded-full font-bold shadow-sm">
                          Aktif
                        </span>
                      )}
                    </div>
                    <p className="text-xs text-slate-500 italic">
                      "{p.reason}"
                    </p>

                    {/* Tombol Edit dan Delete (Hanya muncul saat di-hover) */}
                    <div className="absolute right-2 top-2 opacity-0 group-hover:opacity-100 transition-opacity flex gap-1 bg-white/90 backdrop-blur-sm rounded-lg p-1 shadow-sm border border-slate-100">
                      <button
                        onClick={() => handleEditClick(p)}
                        className="p-1.5 text-slate-400 hover:text-blue-600 rounded-md hover:bg-blue-50 transition-colors"
                        title="Edit Data Freeze"
                      >
                        <Edit3 size={12} />
                      </button>
                      <button
                        onClick={() => handleDeleteClick(p.originalIndex)}
                        className="p-1.5 text-slate-400 hover:text-red-600 rounded-md hover:bg-red-50 transition-colors"
                        title="Hapus Riwayat Freeze"
                      >
                        <Trash2 size={12} />
                      </button>
                    </div>
                  </div>
                );
              })
            )}
          </div>
        </div>
      </div>
    </>
  );
};

// 2.10. Komponen Kontrol Penomoran Halaman (Pagination)

/**
 * Komponen antarmuka untuk navigasi halaman dan pembatasan jumlah baris data.
 * Merupakan shared component yang digunakan juga pada menu File Control.
 */
const PaginationControl = ({
  totalItems,
  itemsPerPage,
  currentPage,
  onPageChange,
  onItemsPerPageChange,
  isDarkMode,
}) => {
  if (totalItems === 0) return null;

  const totalPages =
    itemsPerPage === "all" ? 1 : Math.ceil(totalItems / itemsPerPage);
  const startItem =
    itemsPerPage === "all" ? 1 : (currentPage - 1) * itemsPerPage + 1;
  const endItem =
    itemsPerPage === "all"
      ? totalItems
      : Math.min(currentPage * itemsPerPage, totalItems);

  return (
    <div
      className={`flex flex-col md:flex-row justify-between items-center gap-4 p-4 border-t mt-auto ${isDarkMode ? "border-slate-700 text-slate-400" : "border-slate-200 text-slate-600"}`}
    >
      <div className="text-xs font-medium">
        Menampilkan {startItem}-{endItem} dari {totalItems} data
      </div>

      <div className="flex items-center gap-4">
        <div className="flex items-center gap-2">
          <span className="text-xs">Baris:</span>
          <select
            value={itemsPerPage}
            onChange={(e) => {
              onItemsPerPageChange(
                e.target.value === "all" ? "all" : Number(e.target.value),
              );
              onPageChange(1);
            }}
            className={`text-xs p-1 rounded border cursor-pointer ${isDarkMode ? "bg-slate-800 border-slate-600" : "bg-white border-slate-300"}`}
          >
            <option value={10}>10</option>
            <option value={25}>25</option>
            <option value={50}>50</option>
            <option value="all">Semua</option>
          </select>
        </div>

        <div className="flex items-center gap-1">
          <button
            onClick={() => onPageChange(currentPage - 1)}
            disabled={currentPage === 1}
            className={`p-1 rounded hover:bg-slate-200 dark:hover:bg-slate-700 disabled:opacity-30`}
          >
            <ChevronLeft size={16} />
          </button>
          <span className="text-xs font-mono px-2">
            {currentPage} / {totalPages}
          </span>
          <button
            onClick={() => onPageChange(currentPage + 1)}
            disabled={currentPage === totalPages}
            className={`p-1 rounded hover:bg-slate-200 dark:hover:bg-slate-700 disabled:opacity-30`}
          >
            <ChevronRight size={16} />
          </button>
        </div>
      </div>
    </div>
  );
};

// ==================================================================================
// 3. MARKDOWN RENDERER
// ==================================================================================

const MarkdownRenderer = ({ content, isDarkMode }) => {
  if (!content) {
    return (
      <p className="text-slate-400 italic flex flex-col items-center justify-center h-full gap-2 opacity-60">
        <Sparkles size={24} />
        <span>Belum ada konten ringkasan.</span>
      </p>
    );
  }

  // 3.1. Fungsi Helper: Render String Matematika (LaTeX ke HTML entity/span)
  const renderMathStr = (str) => {
    let html = str
      .replace(
        /\\text\{([^}]+)\}/g,
        '<span class="font-sans normal-case tracking-normal">$1</span>',
      )
      .replace(/\\\\/g, "<br/>")
      .replace(/\\quad/g, "&nbsp;&nbsp;&nbsp;&nbsp;")
      .replace(/\\qquad/g, "&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;")
      .replace(/\*\*([^*]+)\*\*/g, '<strong class="font-bold">$1</strong>')
      .replace(/\*([^*]+)\*/g, '<em class="italic">$1</em>')
      .replace(
        /\\sqrt\{([^}]+)\}/g,
        '&radic;<span class="border-t border-current uppercase pl-px">$1</span>',
      )
      .replace(
        /\\frac\{([^}]+)\}\{([^}]+)\}/g,
        '<span class="inline-flex flex-col text-center align-middle mx-1" style="font-size: 0.8em; line-height: 1.2;"><span class="border-b border-current pb-px">$1</span><span class="pt-px">$2</span></span>',
      )
      .replace(/\^\{([^}]+)\}/g, "<sup>$1</sup>")
      .replace(/\^([a-zA-Z0-9])/g, "<sup>$1</sup>")
      .replace(/_\{([^}]+)\}/g, "<sub>$1</sub>")
      .replace(/_([a-zA-Z0-9])/g, "<sub>$1</sub>")
      .replace(/\\(sin|cos|tan|log|ln|lim)/g, "$1")
      .replace(/\\sum/g, "&sum;")
      .replace(/\\int/g, "&int;")
      .replace(/\\infty/g, "&infin;")
      .replace(/\\partial/g, "&part;")
      .replace(/\\nabla/g, "&nabla;")
      .replace(/\\in\b/g, "&isin;")
      .replace(/\\notin\b/g, "&notin;")
      .replace(/\\cup/g, "&cup;")
      .replace(/\\cap/g, "&cap;")
      .replace(/\\subset/g, "&sub;")
      .replace(/\\supset/g, "&sup;")
      .replace(/\\emptyset/g, "&empty;")
      .replace(/\\exists/g, "&exist;")
      .replace(/\\forall/g, "&forall;")
      .replace(/\\times/g, "&times;")
      .replace(/\\div/g, "&divide;")
      .replace(/\\pm/g, "&plusmn;")
      .replace(/\\mp/g, "&#8723;")
      .replace(/\\leq/g, "&le;")
      .replace(/\\geq/g, "&ge;")
      .replace(/\\neq/g, "&ne;")
      .replace(/\\approx/g, "&approx;")
      .replace(/\\equiv/g, "&equiv;")
      .replace(/\\propto/g, "&prop;")
      .replace(/\\cdot/g, "&sdot;")
      .replace(/\\alpha/g, "&alpha;")
      .replace(/\\beta/g, "&beta;")
      .replace(/\\gamma/g, "&gamma;")
      .replace(/\\Gamma/g, "&Gamma;")
      .replace(/\\delta/g, "&delta;")
      .replace(/\\Delta/g, "&Delta;")
      .replace(/\\theta/g, "&theta;")
      .replace(/\\Theta/g, "&Theta;")
      .replace(/\\pi/g, "&pi;")
      .replace(/\\lambda/g, "&lambda;")
      .replace(/\\mu/g, "&mu;")
      .replace(/\\sigma/g, "&sigma;")
      .replace(/\\omega/g, "&omega;")
      .replace(/\\Omega/g, "&Omega;")
      .replace(/\\phi/g, "&phi;")
      .replace(/\\rho/g, "&rho;")
      .replace(/\\rightarrow/g, "&rarr;")
      .replace(/\\Rightarrow/g, "&rArr;")
      .replace(/\\leftarrow/g, "&larr;")
      .replace(/\\Leftarrow/g, "&lArr;")
      .replace(/\\leftrightarrow/g, "&harr;")
      .replace(/\\Leftrightarrow/g, "&hArr;");
    return { __html: html };
  };

  const blocks = content.split(/(\$\$[\s\S]*?\$\$)/g);

  // 3.2. Fungsi Helper: Parse Inline Styles (Bold, Italic, Link, Code, Inline Math)
  const parseInline = (text) => {
    // PERBAIKAN REGEX 1: Mendukung kurung siku bersarang (nested brackets) di dalam label link
    const parts = text.split(
      /(\*\*.*?\*\*|\*.*?\*|`.*?`|\$.*?\$|\[(?:[^\]]|\](?!\())*\]\([^)]+\))/g,
    );
    return parts.map((part, i) => {
      if (part.startsWith("**") && part.endsWith("**"))
        return (
          <strong
            key={i}
            className={`font-bold ${isDarkMode ? "text-indigo-400" : "text-indigo-700"}`}
          >
            {part.slice(2, -2)}
          </strong>
        );
      if (part.startsWith("*") && part.endsWith("*"))
        return (
          <em key={i} className="italic opacity-80">
            {part.slice(1, -1)}
          </em>
        );
      if (part.startsWith("`") && part.endsWith("`"))
        return (
          <code
            key={i}
            className={`px-1.5 py-0.5 rounded font-mono text-xs border ${isDarkMode ? "bg-slate-700 text-red-300 border-slate-600" : "bg-slate-100 text-red-600 border-slate-200"}`}
          >
            {part.slice(1, -1)}
          </code>
        );
      if (part.startsWith("$") && part.endsWith("$"))
        return (
          <span
            key={i}
            dangerouslySetInnerHTML={renderMathStr(part.slice(1, -1))}
            className={`font-serif italic px-1.5 py-0.5 rounded mx-0.5 font-bold tracking-wide ${isDarkMode ? "bg-slate-800 text-teal-400 border border-slate-700" : "bg-slate-100 text-teal-700 border border-slate-200"}`}
          />
        );

      // PERBAIKAN REGEX 2: Mengekstrak teks dan URL dengan lebih akurat
      const linkMatch = part.match(/^\[((?:[^\]]|\](?!\())*)\]\(([^)]+)\)$/);
      if (linkMatch) {
        const label = linkMatch[1];
        const url = linkMatch[2];
        if (url.startsWith("app:")) {
          return (
            <button
              key={i}
              onClick={() =>
                window.dispatchEvent(
                  new CustomEvent("app-navigate", { detail: url }),
                )
              }
              className={`text-[11px] font-bold px-2 py-0.5 rounded-lg cursor-pointer transition-colors inline-flex items-center gap-1 mx-1 shadow-sm border ${isDarkMode ? "bg-indigo-500/20 text-indigo-300 hover:bg-indigo-500/40 border-indigo-500/30" : "bg-indigo-50 text-indigo-600 hover:bg-indigo-100 border-indigo-200"}`}
            >
              🔗 {label}
            </button>
          );
        }
        return (
          <a
            key={i}
            href={url}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-500 hover:underline inline-flex items-center gap-1"
          >
            🔗 {label}
          </a>
        );
      }
      return part;
    });
  };

  // 3.3. Fungsi Helper: Parse Baris Tabel Markdown
  const parseTableRow = (rowStr) => {
    let s = rowStr.trim();
    if (s.startsWith("|")) s = s.substring(1);
    if (s.endsWith("|")) s = s.substring(0, s.length - 1);
    return s.split("|").map((c) => c.trim());
  };

  return (
    <div
      className={`space-y-3 text-sm leading-relaxed ${isDarkMode ? "text-slate-300" : "text-slate-700"}`}
    >
      {blocks.map((block, blockIndex) => {
        // 3.4. Rendering Block Math ($$ ... $$)
        if (block.startsWith("$$") && block.endsWith("$$")) {
          const mathContent = block.slice(2, -2).trim();
          return (
            <div
              key={blockIndex}
              className={`p-4 rounded-xl text-center font-serif text-lg my-4 overflow-x-auto shadow-sm border ${isDarkMode ? "bg-slate-900/80 text-teal-400 border-slate-700" : "bg-slate-50 text-teal-700 border-slate-200"}`}
            >
              {mathContent.split("\n").map((line, i) => (
                <div
                  key={i}
                  dangerouslySetInnerHTML={renderMathStr(line)}
                  className="my-1 tracking-wider"
                />
              ))}
            </div>
          );
        }

        const lines = block.split("\n");
        const elements = [];
        let tableRows = [];

        // 3.5. Logika Render Tabel
        const flushTable = () => {
          if (tableRows.length > 0) {
            const headers = parseTableRow(tableRows[0]);
            const bodyRows =
              tableRows.length > 1 && tableRows[1].includes("---")
                ? tableRows.slice(2)
                : tableRows.slice(1);
            elements.push(
              <div
                key={`table-${blockIndex}-${elements.length}`}
                className={`overflow-x-auto my-4 rounded-xl border ${isDarkMode ? "border-slate-700" : "border-slate-200"}`}
              >
                <table className="w-full text-left text-sm border-collapse whitespace-nowrap">
                  <thead
                    className={
                      isDarkMode
                        ? "bg-slate-800 text-slate-300"
                        : "bg-slate-50 text-slate-600"
                    }
                  >
                    <tr>
                      {headers.map((h, i) => (
                        <th
                          key={i}
                          className={`p-3 font-bold border-b ${isDarkMode ? "border-slate-700" : "border-slate-200"}`}
                        >
                          {parseInline(h)}
                        </th>
                      ))}
                    </tr>
                  </thead>
                  <tbody
                    className={`divide-y ${isDarkMode ? "divide-slate-700" : "divide-slate-100"}`}
                  >
                    {bodyRows.map((row, i) => (
                      <tr
                        key={i}
                        className={
                          isDarkMode
                            ? "hover:bg-slate-800/50"
                            : "hover:bg-slate-50/50"
                        }
                      >
                        {parseTableRow(row).map((cell, j) => (
                          <td key={j} className="p-3">
                            {parseInline(cell)}
                          </td>
                        ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>,
            );
            tableRows = [];
          }
        };

        // 3.6. Loop Baris per Baris
        for (let i = 0; i < lines.length; i++) {
          const line = lines[i];
          const trimmed = line.trim();

          // Deteksi Tabel
          if (trimmed.startsWith("|") && trimmed.includes("|", 1)) {
            tableRows.push(trimmed);
            continue;
          } else {
            flushTable();
          }

          if (!trimmed) {
            elements.push(<div key={`${blockIndex}-${i}`} className="h-2" />);
            continue;
          }

          // Deteksi Headings (H1, H2, H3)
          if (line.startsWith("# ")) {
            elements.push(
              <h1
                key={`${blockIndex}-${i}`}
                className={`text-2xl font-extrabold mt-6 mb-3 border-b pb-2 ${isDarkMode ? "text-white border-slate-700" : "text-slate-900 border-slate-200"}`}
              >
                {parseInline(line.slice(2))}
              </h1>,
            );
            continue;
          }
          if (line.startsWith("## ")) {
            elements.push(
              <h2
                key={`${blockIndex}-${i}`}
                className={`text-xl font-bold mt-5 mb-2 ${isDarkMode ? "text-white" : "text-slate-800"}`}
              >
                {parseInline(line.slice(3))}
              </h2>,
            );
            continue;
          }
          if (line.startsWith("### ")) {
            elements.push(
              <h3
                key={`${blockIndex}-${i}`}
                className={`text-lg font-bold mt-4 mb-1 ${isDarkMode ? "text-indigo-400" : "text-indigo-600"}`}
              >
                {parseInline(line.slice(4))}
              </h3>,
            );
            continue;
          }

          // Deteksi Blockquote
          if (line.startsWith("> ")) {
            elements.push(
              <blockquote
                key={`${blockIndex}-${i}`}
                className={`border-l-4 pl-4 py-1 my-2 italic ${isDarkMode ? "border-indigo-500 text-slate-400" : "border-indigo-300 text-slate-600"}`}
              >
                {parseInline(line.slice(2))}
              </blockquote>,
            );
            continue;
          }

          // Deteksi Unordered List
          if (trimmed.startsWith("- ") || trimmed.startsWith("* ")) {
            elements.push(
              <div
                key={`${blockIndex}-${i}`}
                className="flex items-start gap-2 ml-2"
              >
                <span
                  className={`mt-2 w-1.5 h-1.5 rounded-full flex-shrink-0 ${isDarkMode ? "bg-indigo-500" : "bg-indigo-600"}`}
                ></span>
                <span className="flex-1">{parseInline(trimmed.slice(2))}</span>
              </div>,
            );
            continue;
          }

          // Deteksi Ordered List
          if (/^\d+\./.test(trimmed)) {
            const number = trimmed.match(/^\d+/)[0];
            const text = trimmed.replace(/^\d+\.\s*/, "");
            elements.push(
              <div
                key={`${blockIndex}-${i}`}
                className="flex items-start gap-2 ml-2"
              >
                <span
                  className={`font-bold font-mono ${isDarkMode ? "text-indigo-400" : "text-indigo-600"}`}
                >
                  {number}.
                </span>
                <span className="flex-1">{parseInline(text)}</span>
              </div>,
            );
            continue;
          }

          // Deteksi Horizontal Rule
          if (trimmed === "---" || trimmed === "***") {
            elements.push(
              <hr
                key={`${blockIndex}-${i}`}
                className={`my-6 ${isDarkMode ? "border-slate-700" : "border-slate-200"}`}
              />,
            );
            continue;
          }

          // Default: Paragraf
          elements.push(<p key={`${blockIndex}-${i}`}>{parseInline(line)}</p>);
        }
        flushTable();

        return <React.Fragment key={blockIndex}>{elements}</React.Fragment>;
      })}
    </div>
  );
};

// ==================================================================================
// 4. NOTES SPACE & AI ASSISTANT
